import os
from google.cloud import storage
from PIL import Image

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Define the source and destination paths
    source_blob_path = f'gs://{bucket_name}/{file_name}'
    temp_file_path = os.path.join('/tmp', file_name)
    
    # Download the image from Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    blob.download_to_filename(temp_file_path)
    
    # Define conversion options (example: resize to 800x600)
    convert_options = '-resize 800x600'
    
    # Run the ImageMagick convert command
    output_file_path = os.path.join('/tmp', f'converted_{file_name}')
    subprocess.call(['convert', temp_file_path, convert_options, output_file_path])
    
    # Upload the converted image back to Cloud Storage
    new_blob = bucket.blob(f'converted/{file_name}')
    new_blob.upload_from_filename(output_file_path)
    
    print(f'Converted {file_name} and uploaded to gs://{bucket_name}/converted/{file_name}')

